    sourceType: 'pubmed', sourceName: 'Nature Protocols', sourceUrl: 'https://pubmed.ncbi.nlm.nih.gov/27888186/',
    doi: '10.1038/nprot.2016.169', pmid: '27888186',
    journal: 'Nature Protocols', publicationYear: 2017,
    authors: ['Hause RJ', 'Pritchard CC', 'Shendure J', 'Salipante SJ'],
