    equipment: ['ABI 3130xl or 3500xL Genetic Analyser', 'Thermocycler', 'Microcentrifuge', 'GeneMapper or GeneMarker software'],
    estimatedTime: '1 day', sampleType: 'FFPE or fresh-frozen tumour DNA', organism: 'Human',
